{
  "name": "Research Assistant Crew",
  "description": "Crew do research i analizy",
  "agents": [
    {
      "role": "Research Specialist",
      "goal": "Przeprowadź dogłębny research na zadany temat",
      "backstory": "Jestem ekspertem w znajdowaniu i analizowaniu informacji z wielu źródeł"
    },
    {
      "role": "Data Analyst",
      "goal": "Przeanalizuj dane i znajdź kluczowe wnioski",
      "backstory": "Specjalizuję się w analizie danych i wykrywaniu trendów"
    },
    {
      "role": "Report Writer",
      "goal": "Stwórz czytelny i wartościowy raport",
      "backstory": "Mam talent do przedstawiania skomplikowanych informacji w prosty sposób"
    }
  ],
  "tasks": [
    {
      "description": "Zbadaj temat: {topic}",
      "agent_role": "Research Specialist",
      "expected_output": "Kompletne zestawienie źródeł i kluczowych informacji"
    },
    {
      "description": "Przeanalizuj zebrane dane i znajdź najważniejsze wnioski",
      "agent_role": "Data Analyst",
      "expected_output": "Lista wniosków z danymi wspierającymi",
      "context": [0]
    },
    {
      "description": "Napisz raport podsumowujący research i analizę",
      "agent_role": "Report Writer",
      "expected_output": "Profesjonalny raport 2-3 strony",
      "context": [0, 1]
    }
  ],
  "process": "sequential"
}

{
  "inputs": {
    "topic": "Wpływ AI na rynek pracy w Polsce w 2025"
  },
  "async_execution": false
}
